    'about.s3.2.table.th5': 'Обґрунтування ВКБ',
    'about.s3.2.td.health_edu': 'Охорона здоров\'я, освіта, спадщина, водопостачання та санітарія',
    'about.s3.2.td.health_edu_base': '30%',
