    'about.s3.1.td.pub_equity_name': '<strong>Capital propio soberano / municipal de contraparte</strong>',
    'about.s3.1.td.pub_equity_def': 'Aportación del Gobierno de Ucrania y de las autoridades oblasales/municipales. A menudo en parte en especie (terreno, estructura existente, permisos regulatorios a valor tasado) y en parte presupuestaria. Las IFI suelen exigir entre el 10 y el 30%. [<code>RDNA3</code>] [<code>EBRD_CASE</code>]',
    'about.s3.1.td.diaspora_name': '<strong>Capital de la diáspora y bonos patrióticos</strong>',
