    'about.s3.1.td.concessional': '<strong>IFI রিয়ায়তি ঋণ</strong>',
    'about.s3.1.td.concessional_code': '<code>concessional_pct</code>',
    'about.s3.1.td.concessional_def': 'সাব-মার্কেট মূল্যে গ্রেস পিরিয়ড সহ দীর্ঘমেয়াদী ঋণ (২০&#8211;৪০ বছর)। বিশ্বব্যাংক, EBRD রিয়ায়তি উইন্ডো, EIB EU4Ukraine, AIIB, NIB; দ্বিপক্ষীয়: KfW Entwicklungsbank, AFD, JICA। ব্লেন্ডেড-ফাইন্যান্স সামাজিক ও পৌরসভা অবকাঠামোতে সাধারণত ২৫&#8211;৪৫%। প্রাথমিক স্তর। [<code>EBRD_CASE</code>] [<code>EIB_UA</code>]',
    'about.s3.1.td.senior_ifi': '<strong>IFI সিনিয়র ঋণ (কাছাকাছি-বাজার)</strong>',
