    'about.s3.1.td.priv_eq_name': '<strong>বেসরকারি ইকুইটি / অবকাঠামো তহবিল</strong>',
    'about.s3.1.td.priv_eq_def': 'ইউক্রেন-নিবেদিত তহবিল (Horizon Capital, Dragon Capital), আঞ্চলিক EM অবকাঠামো, প্রভাব ম্যান্ডেট সহ বৈশ্বিক অবকাঠামো। বেশিরভাগ যুদ্ধবিরতির পরে বা সংকীর্ণ সম্পদ শ্রেণীর জন্য (টেলিকম, লজিস্টিক্স) যেখানে রাজস্ব দৃশ্যমানতা আজকের ঝুঁকিকে ন্যায্যতা দেয়। আস্থা: কম। [<code>EBRD_CASE</code>]',
