    'about.s3.1.td.public_equity_code': '<code>public_equity_pct</code>',
    'about.s3.1.td.public_equity_def': 'ウクライナ中央・州/自治体政府の拠出。多くの場合、一部現物（土地、既存構造物、評価価値での規制承認）、一部予算からの支出。IFIは通常10&#8211;30%を要求。[<code>RDNA3</code>] [<code>EBRD_CASE</code>]',
    'about.s3.1.td.diaspora': '<strong>ディアスポラ資本と愛国債券</strong>',
