    'about.s3.2.td.housing_rat': 'Pilar Perumahan EU + EBRD Green Cities konsesional [<code>EBRD_CASE</code>]',
    'about.s3.2.td.energy': 'Energi — pembangkitan dan jaringan',
    'about.s3.2.td.energy_base': '10%',
    'about.s3.2.td.energy_code': '20%',
    'about.s3.2.td.energy_bbb': '30%',
    'about.s3.2.td.energy_rat': 'Hibah EU untuk transisi terbarukan + EBRD Green Economy [<code>EU_FACILITY</code>]',
    'about.s3.2.td.transport_rev': 'Transportasi — penghasil pendapatan (pelabuhan, jalan tol)',
    'about.s3.2.td.transport_rev_base': '10%',
